const w = await space.current.readWidget("snake-game");
const src = String(w?.content ?? w?.source ?? w?.code ?? "");
const replacements = [
  ["#0f380f", "#9bbc0f"],
  ["#306230", "#8bac0f"],
  ["#8bac0f", "#9bbc0f"],
  ["#c4f0c2", "#dbe98a"],
