const next = JSON.parse(JSON.stringify(original));

function clampTail(segment, factor = 0.6) {
  if (!segment) return segment;
  if (typeof segment === "object") {
    for (const k of ["tailScale", "scale", "size", "radius", "length"]) {
      if (typeof segment[k] === "number") segment[k] = Math.max(segment[k], segment[k] * factor);
    }
  }
  return segment;
}

if (Array.isArray(next?.snake?.body)) {
  const body = next.snake.body;
  for (let i = 0; i < body.length; i++) {
    const t = i / Math.max(1, body.length - 1);
    const floor = 0.6;
    const scale = Math.max(floor, 1 - t * (1 - floor));
    body[i] = clampTail(body[i], scale);
    if (typeof body[i] === "object" && body[i] !== null) {
      body[i].tailScale = body[i].tailScale ?? scale;
      body[i].tailScale = Math.max(body[i].tailScale, 0.6);
    }
  }
}

if (Array.isArray(next?.segments)) {
  const segs = next.segments;
  for (let i = 0; i < segs.length; i++) {
    const t = i / Math.max(1, segs.length - 1);
    const floor = 0.6;
    const scale = Math.max(floor, 1 - t * (1 - floor));
    segs[i] = clampTail(segs[i], scale);
    if (typeof segs[i] === "object" && segs[i] !== null) {
      segs[i].tailScale = segs[i].tailScale ?? scale;
      segs[i].tailScale = Math.max(segs[i].tailScale, 0.6);
    }
  }
}

