Patching the Snake game background to a Nokia-like green display...
_____javascript
const widget = space.chat.transient.get("snake-game") || space.current.transient?.get?.("snake-game") || space.current.widget?.("snake-game");
if (!widget) return "snake-game widget not found in transient context";

const css = `
:root, .snake-game, .snake-widget, canvas, body {
  background: #9bbf5a !important;
}
.snake-game, .snake-widget {
  color: #1f2d16 !important;
  font-family: monospace !important;
}
canvas {
  image-rendering: pixelated !important;
  box-shadow: inset 0 0 0 2px rgba(31,45,22,0.35) !important;
}
`;

const patchTargets = [];
if (widget.css !== undefined) patchTargets.push(["css", css]);
if (widget.styles !== undefined) patchTargets.push(["styles", css]);
if (widget.style !== undefined) patchTargets.push(["style", { ...(widget.style || {}), background: "#9bbf5a", color: "#1f2d16" }]);

if (!patchTargets.length) return "Widget loaded, but no writable style field found.";

for (const [key, value] of patchTargets) widget[key] = value;

return "patched";

